const items = $input.all();
const extractAccountIdsByPlatform = jsonData => {
  const data = Array.isArray(jsonData) ? jsonData[0] : jsonData;
  if (!data['success'] || !data['results'] || !data['results']['accounts']) {
    throw new Error('Invalid response format or unsuccessful API call');
  }
  const accounts = data['results']['accounts'];
  const platforms = ['facebook', 'google', 'instagram', 'tiktok', 'pinterest', 'linkedin','threads','bluesky'];
  const platformAccounts = Object.fromEntries(
    platforms.map(p => [p, accounts.filter(account => (account['platform'] || '').toLowerCase() === p).map(account => ({
      id: account['id'],
      originId: account['originId'],
      name: account['name'],
      type: account['type'],
      isExpired: account['isExpired']
    }))])
  );
  return platformAccounts;
};
const getAccountIdsByPlatform = (jsonData, platform) => {
  const platformAccounts = extractAccountIdsByPlatform(jsonData);
  const platformKey = (platform || '').toLowerCase();
  if (!Object.prototype.hasOwnProperty.call(platformAccounts, platformKey)) {
    throw new Error('Platform ' + platform + ' not supported. Available platforms: ' + Object.keys(platformAccounts).join(', '));
  }
  return platformAccounts[platformKey].map(account => account['id']);
};
const getAllAccountIds = jsonData => {
  const platformAccounts = extractAccountIdsByPlatform(jsonData);
  return Object.fromEntries(
    Object.keys(platformAccounts).map(platform => [platform, platformAccounts[platform].map(account => account['id'])])
  );
};
return items.map(item => {
  const jsondata = item.json?.jsondata || item.json;
  const byPlatform = extractAccountIdsByPlatform(jsondata);
  const allIds = getAllAccountIds(jsondata);
  const facebookIds = getAccountIdsByPlatform(jsondata, 'facebook');
  const instagramIds = getAccountIdsByPlatform(jsondata, 'instagram');
  return {
    json: {
      by: byPlatform,
      allIds: allIds,
      facebookIds: facebookIds,
      instagramIds: instagramIds
    }
  };
});

const items = $input.all();
return items.map(item => {
